function normalizeLineEndings(e){return e.replace(/\r\n/g,"\n").replace(/\r/g,"\n")}function getLanguageInfo(e){return e.endsWith(".jsx")?{className:"language-jsx",lang:"jsx"}:{className:"language-python",lang:"python"}}function renderCode(e,t,n){if(e.textContent=t,"undefined"==typeof Prism||!Prism.languages[n])return;const o=Prism.languages[n],a=t.split("\n").map(e=>0===e.length?"":Prism.highlight(e,o,n)).join("\n");e.innerHTML=a}function openCode(e){const t=document.getElementById("codeModal"),n=document.getElementById("modalTitle"),o=document.getElementById("codeBlock"),a=o?.closest("pre");if(!t||!n||!o)return;n.textContent=e,o.textContent="Carregando código...";const{className:r,lang:s}=getLanguageInfo(e);o.className=r,a&&(a.className=r),fetch(e).then(e=>{if(!e.ok)throw new Error("Arquivo não encontrado");return e.text()}).then(e=>{renderCode(o,normalizeLineEndings(e),s)}).catch(e=>{o.textContent=`ERRO: ${e.message}\n\nArquivo ausente no repositório.`}),t.classList.add("show"),t.setAttribute("aria-hidden","false")}function closeCode(){const e=document.getElementById("codeModal");e&&(e.classList.remove("show"),e.setAttribute("aria-hidden","true"))}document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("codeModal");e&&(e.addEventListener("click",e=>{e.target===e.currentTarget&&closeCode()}),document.addEventListener("keydown",e=>{"Escape"===e.key&&closeCode()}))});
